import {
  css,
  customElement,
  html,
  state,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type {
  UUIBooleanInputEvent,
  UUIInputEvent,
  UUISelectEvent,
} from "@umbraco-cms/backoffice/external/uui";
import type {
  UmbPropertyDatasetElement,
  UmbPropertyValueData,
} from "@umbraco-cms/backoffice/property";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import { tryExecute } from "@umbraco-cms/backoffice/resources";
import type {
  ApiError,
  FieldCondition,
  Setting,
} from "@umbraco-forms/generated";
import {
  FieldConditionActionType,
  FieldConditionLogicType,
  FormService,
} from "@umbraco-forms/generated";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { UmbId } from "@umbraco-cms/backoffice/id";
import type {
  FormsEditWorkflowModalData,
  FormsEditWorkflowModalValue,
} from "../token/form-edit-workflow-modal.token.js";
import { ProviderTypeSettingsHelper } from "../../section/provider-types/provider-type-settings-helper.class.js";
import {
  ConditionAppliedTo,
  type FormsEditConditionsElement,
} from "./form-edit-conditions.element.js";

const elementName = "form-edit-workflow-modal";

@customElement(elementName)
export class FormsEditWorkflowModalElement extends UmbModalBaseElement<
  FormsEditWorkflowModalData,
  FormsEditWorkflowModalValue
> {
  #providerTypeSettingsHelper?: ProviderTypeSettingsHelper;
  #workflowCollections: Array<string> = ["onSubmit", "onApprove", "onReject"];

  @state()
  _settingValues: Array<UmbPropertyValueData> = [];

  @state()
  _settingsConfig: Array<{ alias: string; value: UmbPropertyEditorConfig }> = [];

  @state()
  _settingsConfigLoaded: boolean = false;;

  @state()
  _conditionEnabled = false;

  async connectedCallback(): Promise<void> {
    super.connectedCallback();
    this.#providerTypeSettingsHelper = new ProviderTypeSettingsHelper(
      this,
      this.data!.workflowType,
      "formProviderWorkflows"
    );
    await this.#providerTypeSettingsHelper.loadSettingValueConverterApis();
    await this.#initializeSettingsForEditor();

    this._settingsConfig =
      await this.#providerTypeSettingsHelper.getSettingsConfig(
        this._settingValues,
        this.data!.workflowType.settings
      );
    this._settingsConfigLoaded = true;

    this._conditionEnabled = this.value?.condition?.enabled ?? false;
  }

  async #initializeSettingsForEditor() {
    // ensure all settings from the workflow type exist on the value
    // when the modal is submitted, any settings with the default value
    // are ignored and not persisted.
    const settings = { ...this.value.settings };
    this.data?.workflowType.settings.forEach((setting) => {
      if (settings[setting.alias]) return;

      settings[setting.alias] = setting.defaultValue;
    });

    this._settingValues =
      await this.#providerTypeSettingsHelper!.getSettingValues(settings);
  }

  #onNameChange(e: UUIInputEvent) {
    const name = e.target.value.toString();
    this.modalContext?.updateValue({ name });
  }

  #onIncludeSensitiveDataChange(e: UUIBooleanInputEvent) {
    const includeSensitiveData = e.target.checked;
    this.modalContext?.updateValue({ includeSensitiveData });
  }

  #onActiveChange(e: UUIBooleanInputEvent) {
    const active = e.target.checked;
    this.modalContext?.updateValue({ active });
  }

  #onStageChange(e: UUISelectEvent) {
    const collectionName = e.target.value.toString();
    this.modalContext?.updateValue({ collectionName });
  }

  async #onSettingsChange(e: CustomEvent) {
    const value = (e.target as UmbPropertyDatasetElement).value;
    this._settingValues = value;
  }

  #onConditionEnabledChange(e: UUIBooleanInputEvent) {
    this._conditionEnabled = e.target.checked;

    const condition =
      structuredClone(this.value.condition) || this.#scaffoldCondition();

    condition.enabled = this._conditionEnabled;
    this.modalContext?.updateValue({ condition });
  }

  #scaffoldCondition(): FieldCondition {
    return {
      id: UmbId.new(),
      enabled: false,
      actionType: FieldConditionActionType.SHOW,
      logicType: FieldConditionLogicType.ALL,
      rules: [],
    };
  }

  #onConditionChange(e: CustomEvent) {
    const condition = (e.target as FormsEditConditionsElement).value;
    this.modalContext?.updateValue({ condition });
  }

  async #submitModal() {
    const settings =
      await this.#providerTypeSettingsHelper!.getUpdatedSettingsForPersistence(
        this._settingValues,
        this.data!.workflowType.settings
      );

    const validateRequest = {
      id: this.data!.workflowType.id,
      requestBody: {
        name: this.value!.name,
        settings,
      },
    };
    const { error } = await tryExecute(
      FormService.postFormWorkflowByIdValidateSettings(validateRequest)
    );
    if (error) {
      const notification =
        this.#providerTypeSettingsHelper!.createValidationErrorNotification(
          "formWorkflows_saveFailedTitle",
          error as ApiError
        );

      const notificationContext = await this.getContext(
        UMB_NOTIFICATION_CONTEXT
      );
      notificationContext.peek("danger", notification);
    } else {
      this.modalContext?.updateValue({ settings });
      this._submitModal();
    }
  }

  render() {
    return html`<umb-body-layout
      headline=${this.localize.term("formEdit_editWorkflow")}
    >
      <div id="main">
        <uui-box>
          <umb-property-layout
            alias="name"
            .label=${this.localize.term("formWorkflows_workflowNameLabel")}
            .description=${this.localize.term(
              "formWorkflows_workflowNameDescription"
            )}
          >
            <uui-input
              slot="editor"
              .value=${this.value?.name}
              @change=${this.#onNameChange}
              label="name"
            ></uui-input>
          </umb-property-layout>

          <umb-property-layout
            alias="workflowType"
            .label=${this.localize.term("formWorkflows_workflowTypeLabel")}
            .description=${this.localize.term(
              "formWorkflows_workflowTypeDescription"
            )}
          >
            <div slot="editor" id="workflowType">
              <span class="icon"
                ><uui-icon name=${this.data?.workflowType.icon ?? ""}></uui-icon
              ></span>
              <div class="info">
                <div>${this.data?.workflowType.name}</div>
                <small>${this.data?.workflowType.description}</small>
              </div>
            </div>
          </umb-property-layout>

          <umb-property-layout
            alias="active"
            .label=${this.localize.term("formWorkflows_activeLabel")}
            .description=${this.localize.term(
              "formWorkflows_activeDescription"
            )}
          >
            <uui-toggle
              slot="editor"
              ?checked=${this.value?.active}
              @change=${this.#onActiveChange}
              label="${this.localize.term("formWorkflows_activeLabel")}"
            ></uui-toggle>
          </umb-property-layout>

          <umb-property-layout
            alias="sensitiveData"
            .label=${this.localize.term(
              "formWorkflows_includeSensitiveDataLabel"
            )}
            .description=${this.localize.term(
              "formWorkflows_includeSensitiveDataDescription"
            )}
          >
            <uui-toggle
              slot="editor"
              ?checked=${this.value?.includeSensitiveData}
              @change=${this.#onIncludeSensitiveDataChange}
              label="${this.localize.term(
                "formWorkflows_includeSensitiveDataLabel"
              )}"
            ></uui-toggle>
          </umb-property-layout>

          ${when(
            this.data && !this.data.isNew,
            () => html`<umb-property-layout alias="stage" label="Stage">
              <uui-select
                label="Stage"
                slot="editor"
                @change=${this.#onStageChange}
                .options=${this.#workflowCollections.map((s) => ({
                  name: s,
                  value: s,
                  selected: this.value.collectionName === s,
                }))}
              >
              </uui-select>
            </umb-property-layout>`
          )}

          ${when(
            this.#providerTypeSettingsHelper && this.value && this._settingsConfigLoaded,
            () => html`
              <umb-property-dataset
                .value=${this._settingValues}
                @change=${this.#onSettingsChange}
              >
                ${this.data!.workflowType.settings.map(
                  (setting) => html`
                    <umb-property
                      ?inert=${setting.isReadOnly}
                      label=${this.#providerTypeSettingsHelper!.getLocalizedSettingDetail(
                        setting,
                        "Label",
                        setting.name
                      )}
                      description=${this.#providerTypeSettingsHelper!.getLocalizedSettingDetail(
                        setting,
                        "Description",
                        setting.description
                      )}
                      alias=${setting.alias}
                      .config=${this.#providerTypeSettingsHelper!.getPropertyConfigForSetting(this._settingsConfig, setting)}
                      .appearance=${this.#providerTypeSettingsHelper!.getPropertyAppearanceForSetting(setting.view)}
                      property-editor-ui-alias=${setting.view}
                    >
                    </umb-property>
                  `
                )}
              </umb-property-dataset>`
          )}

          <umb-property-layout
            alias="conditions"
            .label=${this.localize.term("formConditions_title")}
          >
            <div slot="editor">
              <uui-toggle
                ?checked=${this._conditionEnabled}
                .label=${this._conditionEnabled ? "On" : "Off"}
                @change=${this.#onConditionEnabledChange}
              ></uui-toggle>
              ${when(
                this._conditionEnabled,
                () =>
                  html`<form-edit-conditions
                    .value=${this.value.condition}
                    .fields=${this.data?.fields ?? []}
                    .appliedTo=${ConditionAppliedTo.WORKFLOW}
                    @change=${this.#onConditionChange}
                  ></form-edit-conditions>`
              )}
            </div>
          </umb-property-layout>
        </uui-box>
      </div>
      <div slot="actions">
        <uui-button
          label=${this.localize.term("general_close")}
          @click=${this._rejectModal}
        ></uui-button>
        <uui-button
          color="positive"
          look="primary"
          label=${this.localize.term("general_submit")}
          @click=${this.#submitModal}
        ></uui-button>
      </div>
    </umb-body-layout>`;
  }

  static styles = [
    css`
      [inert] {
        opacity: 0.5;
      }

			#workflowType {
				text-decoration: none;
				color: inherit;
				align-self: stretch;
				line-height: normal;

				display: flex;
				position: relative;
				align-items: center;
			}

      #workflowType .icon {
        margin-right: 10px;
      }

      #workflowType .icon uui-icon {
        width: 1.6em;
        height: 1.6em;
    `,
  ];
}

export default FormsEditWorkflowModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsEditWorkflowModalElement;
  }
}
